// ─── SEED RUNNER ─────────────────────────────────────────────────────────────
const allProducts = [
  ...menProducts,
  ...womenProducts,
  ...kidsProducts,
  ...sneakersProducts,
  ...accessoriesProducts,
];

async function seed() {
  try {
    console.log('Connecting to MongoDB...');
    await mongoose.connect(MONGODB_URI);
    console.log('Connected! Clearing old products...');

    await mongoose.connection.db.collection('products').deleteMany({});
    console.log('Old products cleared. Inserting new products...');

    const preparedProducts = allProducts.map(p => ({
      ...p,
      slug: makeSlug(p.name),
      createdAt: new Date(),
      updatedAt: new Date(),
    }));

    const result = await mongoose.connection.db.collection('products').insertMany(preparedProducts);
    console.log(`Successfully seeded ${result.insertedCount} products!`);

    // Summary by category
    const summary = {};
    preparedProducts.forEach(p => {
      summary[p.category] = (summary[p.category] || 0) + 1;
    });
    console.log('Breakdown by category:', summary);

    process.exit(0);
  } catch (error) {
    console.error('Seeding failed:', error);
    process.exit(1);
  }
}

seed();
